#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int x[n], y[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        int areas[n * (n - 1) / 2];
        int index = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                areas[index++] = (abs(x[i] - x[j]) + abs(y[i] - y[j])) / 2;
            }
        }
        qsort(areas, n * (n - 1) / 2, sizeof(int), compare);
        int maxArea = 0;
        for (int i = 0; i < k; i++) {
            maxArea = max(maxArea, areas[n * (n - 1) / 2 - i - 1]);
        }
        printf("%d\n", maxArea);
    }
    return 0;
}

