import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            int[] x = new int[n];
            int[] y = new int[n];
            for (int i = 0; i < n; i++) {
                x[i] = scanner.nextInt();
                y[i] = scanner.nextInt();
            }
            int[] areas = new int[n * (n - 1) / 2];
            int index = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    areas[index++] = (Math.abs(x[i] - x[j]) + Math.abs(y[i] - y[j])) / 2;
                }
            }
            Arrays.sort(areas);
            int maxArea = 0;
            for (int i = 0; i < k; i++) {
                maxArea = Math.max(maxArea, areas[n * (n - 1) / 2 - i - 1]);
            }
            System.out.println(maxArea);
        }
    }
}

