const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [n, k] = nextInts();
    let x = new Array(n);
    let y = new Array(n);
    for (let i = 0; i < n; i++) {
        [x[i], y[i]] = nextInts();
    }
    let areas = [];
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            areas.push((Math.abs(x[i] - x[j]) + Math.abs(y[i] - y[j])) / 2);
        }
    }
    areas.sort((a, b) => a - b);
    let maxArea = 0;
    for (let i = 0; i < k; i++) {
        maxArea = Math.max(maxArea, areas[n * (n - 1) / 2 - i - 1]);
    }
    console.log(maxArea);
}

